// List of valid ISO currency codes (extend if needed)
const validCurrencies = [
  "USD","EUR","GBP","JPY","AUD","NZD","CAD","CHF",
  "CNY","SEK","NOK","DKK","ZAR","MXN","HKD","SGD"
];

// Special mappings for indices/CFDs
const specialMappings = {
  "US30": [
    "USD",
    "Quote is not a currency of a country, so there are no future events. Only use the base currency to analyse."
  ],
  "US500": [
    "USD",
    "Quote is not a currency of a country, so there are no future events. Only use the base currency to analyse."
  ],
  "USTEC": [
    "USD",
    "Quote is not a currency of a country, so there are no future events. Only use the base currency to analyse."
  ],
  "DE30": [
    "EUR",
    "Quote is not a currency of a country, so there are no future events. Only use the base currency to analyse."
  ],
  "UK30": [
    "GBP",
    "Quote is not a currency of a country, so there are no future events. Only use the base currency to analyse."
  ],
};

const items = $input.all();

return items.map(item => {
  const symbol = item.json.symbol || "";
  let base = "";
  let quote = "";

  if (specialMappings[symbol]) {
    [base, quote] = specialMappings[symbol];
  } else if (symbol.length === 6) {
    base = symbol.substring(0, 3);
    quote = symbol.substring(3, 6);
  } else if (symbol.length > 3) {
    base = symbol.substring(0, symbol.length - 3);
    quote = symbol.substring(symbol.length - 3);
  }

  // Validate against currency list and replace with explanation if invalid
  if (!validCurrencies.includes(base)) {
    base =
      "Base is not a currency of a country, so there are no future events. Only use the quote currency to analyse.";
  }
  if (!validCurrencies.includes(quote)) {
    quote =
      "Quote is not a currency of a country, so there are no future events. Only use the base currency to analyse.";
  }

  return {
    json: {
      symbol,
      base,
      quote,
    }
  };
});

