// For escaping JSON strings (adding escape characters)
const inputData = $input.all();
const outputData = [];

for (const item of inputData) {
  try {
    // Get the JSON data from the item
    const jsonData = item.json;

    // Method 1: Escape JSON string (if you have a JSON string that needs escaping)
    let escapedJson = '';
    if (typeof jsonData === 'string') {
      escapedJson = jsonData
        .replace(/\\/g, '\\\\')   // Escape backslashes
        .replace(/"/g, '\\"')     // Escape double quotes
        .replace(/'/g, "\\'")     // Escape single quotes
        .replace(/\n/g, '\\n')    // Escape newlines
        .replace(/\r/g, '\\r')    // Escape carriage returns
        .replace(/\t/g, '\\t')    // Escape tabs
        .replace(/\b/g, '\\b')    // Escape backspace
        .replace(/\f/g, '\\f');   // Escape form feed
    } else {
      // Method 2: Convert object to escaped JSON string
      escapedJson = JSON.stringify(jsonData)
        .replace(/\\/g, '\\\\')
        .replace(/"/g, '\\"');
    }

    outputData.push({
      json: {
        original: jsonData,
        escaped: escapedJson,
        ready_for_api: JSON.stringify(jsonData) // Properly formatted JSON string
      }
    });

  } catch (error) {
    outputData.push({
      json: {
        error: `Failed to escape JSON: ${error.message}`,
        original: item.json
      }
    });
  }
}

return outputData;

